import{_ as t,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as s,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Yandex Channel ထည့်သွင်းခြင်း","description":"","frontmatter":{},"headers":[],"relativePath":"my/upload/yandex.md","filePath":"my/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"my/upload/yandex.md"};function p(c,e,h,u,m,x){return s(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="yandex-channel-ထည့်သွင်းခြင်း" tabindex="-1">Yandex Channel ထည့်သွင်းခြင်း <a class="header-anchor" href="#yandex-channel-ထည့်သွင်းခြင်း" aria-label="Permalink to &quot;Yandex Channel ထည့်သွင်းခြင်း&quot;">​</a></h1><h2 id="စမလုပ်ခင်-လိုအပ်တာတွေ" tabindex="-1">စမလုပ်ခင် လိုအပ်တာတွေ <a class="header-anchor" href="#စမလုပ်ခင်-လိုအပ်တာတွေ" aria-label="Permalink to &quot;စမလုပ်ခင် လိုအပ်တာတွေ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>လိုအပ်ချက်</th><th>ဘာကြောင့်လိုလဲ</th></tr></thead><tbody><tr><td>Yandex account</td><td>sign in ဝင်ရန်နှင့် Yandex Disk authorize လုပ်ရန်</td></tr><tr><td>Yandex OAuth app</td><td><code>Client ID</code> နဲ့ <code>Client Secret</code> generate လုပ်ရန်</td></tr><tr><td>သင့် ImgBed domain</td><td>OAuth redirect URI အတွက်</td></tr><tr><td>Yandex Disk storage ရရှိနိုင်မှု</td><td>file storage location အဖြစ်သုံးရန်</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-yandex-oauth-app-ဖန်တီးပါ" tabindex="-1">Step 1: Yandex OAuth App ဖန်တီးပါ <a class="header-anchor" href="#step-1-yandex-oauth-app-ဖန်တီးပါ" aria-label="Permalink to &quot;Step 1: Yandex OAuth App ဖန်တီးပါ&quot;">​</a></h3><ol><li>Yandex OAuth app creation page ကိုဖွင့်ပါ:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>sign in page ကို redirect ဖြစ်လျှင် Yandex account နဲ့အရင် sign in ဝင်ပါ။</li><li>app အသစ်ဖန်တီးပါ။</li><li>app ကိုမှတ်မိလွယ်တဲ့အမည်ပေးပါ၊ ဥပမာ <code>imgbed-yandex</code>။</li><li>callback သို့မဟုတ် redirect URL settings ကိုရှာပါ။</li><li>ထည့်ပါ:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="step-2-permissions-confirm-လုပ်ပါ" tabindex="-1">Step 2: Permissions Confirm လုပ်ပါ <a class="header-anchor" href="#step-2-permissions-confirm-လုပ်ပါ" aria-label="Permalink to &quot;Step 2: Permissions Confirm လုပ်ပါ&quot;">​</a></h3><p>လက်ရှိ ImgBed Yandex integration အတွက် <code>Yandex.Disk REST API</code> အောက်မှာ ဒီ permissions လေးခုထားပါ:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>ImgBed ကို app folder ထဲ files သိမ်းခွင့်ပေးသည်</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>files နဲ့ download links ဖတ်သည်</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>files upload လုပ်သည်၊ folders ဖန်တီးသည်၊ files delete လုပ်သည်</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>disk quota နဲ့ used space ဖတ်သည်</td></tr></tbody></table><p><code>Yandex ID API</code> အောက်မှာ ဒီ permissions တွေမြင်လျှင် optional ဖြစ်ပါတယ်:</p><table tabindex="0"><thead><tr><th>Permission Text</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Optional</td></tr><tr><td><code>Access to email address</code></td><td>Optional</td></tr></tbody></table><p>core upload, download, deletion, quota features တွေက အပေါ်က <code>Yandex.Disk REST API</code> permissions လေးခုကိုအဓိကမှီခိုပါတယ်။</p><p><img src="'+t+'" alt="Configure Yandex Disk permissions" loading="lazy"></p><h3 id="step-3-app-credentials-copy-လုပ်ပါ" tabindex="-1">Step 3: App Credentials Copy လုပ်ပါ <a class="header-anchor" href="#step-3-app-credentials-copy-လုပ်ပါ" aria-label="Permalink to &quot;Step 3: App Credentials Copy လုပ်ပါ&quot;">​</a></h3><p>app ဖန်တီးပြီးနောက် copy လုပ်ပါ:</p><table tabindex="0"><thead><tr><th>Yandex Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Record Client ID and Secret" loading="lazy"></p><h3 id="step-4-imgbed-မှာ-yandex-channel-ဖြည့်ပါ" tabindex="-1">Step 4: ImgBed မှာ Yandex Channel ဖြည့်ပါ <a class="header-anchor" href="#step-4-imgbed-မှာ-yandex-channel-ဖြည့်ပါ" aria-label="Permalink to &quot;Step 4: ImgBed မှာ Yandex Channel ဖြည့်ပါ&quot;">​</a></h3><p>Upload Settings မှာ <code>Yandex</code> ကိုရွေးပြီး:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>မှတ်မိလွယ်တဲ့အမည်၊ ဥပမာ <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td>Yandex app <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>Yandex app <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>အခုခဏဗလာထားပါ</td></tr><tr><td>Root directory</td><td>Optional။ default က <code>imgbed</code>။</td></tr></tbody></table><p><img src="'+d+'" alt="Edit channel config" loading="lazy"></p><h3 id="step-5-refresh-token-ရယူပါ" tabindex="-1">Step 5: Refresh Token ရယူပါ <a class="header-anchor" href="#step-5-refresh-token-ရယူပါ" aria-label="Permalink to &quot;Step 5: Refresh Token ရယူပါ&quot;">​</a></h3><ol><li>ImgBed မှာ <code>Get Token</code> ကိုနှိပ်ပါ။</li><li>connect လုပ်ချင်တဲ့ Yandex account ထဲ sign in ဝင်ပါ။</li><li>authorization prompt ကို approve လုပ်ပါ။</li><li>callback page မှာ <code>Refresh Token</code> ပြပါမယ်။</li><li>အဲဒါကို copy လုပ်ပါ။</li><li>ImgBed ကိုပြန်သွားပြီး <code>Refresh Token</code> field ထဲ paste လုပ်ပါ။</li></ol><p><img src="'+n+`" alt="Copy refresh token after authorization" loading="lazy"></p><h3 id="step-6-channel-save-လုပ်ပါ" tabindex="-1">Step 6: Channel Save လုပ်ပါ <a class="header-anchor" href="#step-6-channel-save-လုပ်ပါ" aria-label="Permalink to &quot;Step 6: Channel Save လုပ်ပါ&quot;">​</a></h3><p>fields အားလုံးဖြည့်ပြီးနောက် channel ကို save လုပ်ပါ။</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Yandex OAuth Console ဖွင့်ပါ</span></span>
<span class="line"><span>-&gt; app ဖန်တီးပါ</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/yandex/callback ထည့်ပါ</span></span>
<span class="line"><span>-&gt; Yandex Disk permissions confirm လုပ်ပါ</span></span>
<span class="line"><span>-&gt; Client ID နဲ့ Client Secret copy လုပ်ပါ</span></span>
<span class="line"><span>-&gt; ImgBed မှာ Client ID / Client Secret ထည့်ပါ</span></span>
<span class="line"><span>-&gt; Get Token ကိုနှိပ်ပါ</span></span>
<span class="line"><span>-&gt; callback page မှ Refresh Token copy လုပ်ပါ</span></span>
<span class="line"><span>-&gt; ImgBed မှာ paste လုပ်ပြီး save လုပ်ပါ</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const k=o(r,[["render",p]]);export{f as __pageData,k as default};
